+      : TValue extends readonly (infer TValue)[]
+        ? ResolveRecur<TValue, TRecur>[]
+        : TValue extends object
+          ? { [TKey in keyof TValue]: ResolveRecur<TValue[TKey], TRecur> }
+          : TValue;
+
+/**
+ * Recursive schema interface.
+ */
+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    ResolveRecur<InferInput<TWrapped>, RecursiveSchema<TWrapped>>,
+    ResolveRecur<InferOutput<TWrapped>, RecursiveSchema<TWrapped>>,
+    InferIssue<TWrapped>
+  > {}
+
+/**
+ * Placeholder for a reference to the schema passed to {@link recursive}.
+ */
+export const Recur: RecurSchema = {
+  kind: 'schema',
+  type: 'recur',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  '~standard': undefined as never,
+  '~run'() {
+    throw new Error('The Recur placeholder must be wrapped with recursive.');
+  },
+};
+
+/**
+ * Creates a recursive schema from a schema containing {@link Recur}.
+ *
+ * @param wrapped The schema to make recursive.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  return _recursive(wrapped) as RecursiveSchema<TWrapped>;
+}
+
+/**
+ * Resolves the recursive placeholders in a schema without mutating it.
+ */
+export function _recursive<TSchema extends object>(schema: TSchema): TSchema {
+  const recursiveSchema: Record<PropertyKey, unknown> = {};
+  const references = new WeakMap<object, object>();
+
+  const clone = (value: unknown): unknown => {
+    if (value === Recur) {
+      return recursiveSchema;
+    }
+    if (!value || typeof value !== 'object') {
+      return value;
+    }
+    const reference = references.get(value);
+    if (reference) {
+      return reference;
+    }
+    const copy: Record<PropertyKey, unknown> = Array.isArray(value) ? [] : {};
+    references.set(value, copy);
+    const descriptors = Object.getOwnPropertyDescriptors(value);
+    for (const key of Reflect.ownKeys(descriptors)) {
+      const descriptor = descriptors[key]!;
+      if ('value' in descriptor) {
+        descriptor.value = clone(descriptor.value);
+      }
+    }
+    Object.defineProperties(copy, descriptors);
+    return copy;
+  };
+
+  Object.defineProperties(recursiveSchema, Object.getOwnPropertyDescriptors(clone(schema)));
+  return recursiveSchema as TSchema;
+}
