            (!config.abortEarly && !config.abortPipeEarly)
          ) {
            // @ts-expect-error
            dataset = item['~run'](dataset, config);
          }
        }
      }

      // Return output dataset
      // @ts-expect-error
      return dataset as OutputDataset<unknown, BaseIssue<unknown>>;
    },
  };
}
import { describe, expect, test } from 'vitest';
import { transform } from '../../actions/index.ts';
import { parse } from '../parse/index.ts';
import { pipe } from '../pipe/index.ts';
import {
  array,
  intersect,
  map,
  object,
  record,
  set,
  string,
} from '../../schemas/index.ts';
import { Recur, recursive } from './recursive.ts';

describe('recursive', () => {
  test('should resolve recursive object and array positions', () => {
    const schema = recursive(
      object({ value: string(), children: array(Recur) })
    );
    expect(
      parse(schema, {
        value: 'root',
        children: [{ value: 'child', children: [] }],
      })
    ).toStrictEqual({
      value: 'root',
      children: [{ value: 'child', children: [] }],
    });
  });

  test('should resolve recursive record, map and set value positions', () => {
    expect(parse(recursive(record(string(), Recur)), { child: {} })).toStrictEqual(
      { child: {} }
    );
    expect(
      parse(recursive(map(string(), Recur)), new Map([['child', new Map()]]))
    ).toStrictEqual(new Map([['child', new Map()]]));
    expect(parse(recursive(set(Recur)), new Set([new Set()]))).toStrictEqual(
      new Set([new Set()])
    );
  });

  test('should compose through pipe and intersect', () => {
    const piped = recursive(
      pipe(
        object({ children: array(Recur) }),
        transform((input) => ({ ...input, count: input.children.length }))
      )
    );
    expect(parse(piped, { children: [{ children: [] }] })).toStrictEqual({
      children: [{ children: [], count: 0 }],
      count: 1,
    });

    const intersected = recursive(
      intersect([object({ children: array(Recur) }), object({})])
    );
    expect(parse(intersected, { children: [{ children: [] }] })).toStrictEqual({
      children: [{ children: [] }],
    });
  });
});

